        throw new IllegalArgumentException("Length " + length + " must be at least 2");
    }

    int end = offset + length;
    int start = offset;
    long result = 0;

    if (buffer[start] == 0) {
        return 0L;
    }

    // Skip the leading spaces
    while (start < end && buffer[start] == ' ') {
        start++;
    }

    // Validate there is still space to parse after trimming
    if (start >= end) {
        throw new IllegalArgumentException("Buffer contains only spaces or NULs");
    }

    // Determine proper end after stripping trailing NULs and spaces
    byte trailer = buffer[end - 1];
    while (end > start && (trailer == 0 || trailer == ' ')) {
        end--;
        trailer = buffer[end - 1];
    }

    // Parse the valid octal input
    for (; start < end; start++) {
        final byte currentByte = buffer[start];
        if (currentByte < '0' || currentByte > '7') {
            throw new IllegalArgumentException(
                exceptionMessage(buffer, offset, length, start, currentByte)
            );
        }
        result = (result << 3) + (currentByte - '0'); // Convert to decimal

        // Overflow detection for 36-bit octal
        if ((result >>> 36) != 0) {
            throw new IllegalArgumentException("Octal value exceeds maximum size");
        }
    }

    return result;
}

public static long parseOctal(final byte[] buffer, final int offset, final int length) {
    if (buffer == null) {
        throw new IllegalArgumentException("Buffer is null");
    }
    if (length < 2) {
        throw new IllegalArgumentException("Length " + length + " must be at least 2");
    }
    long result = 0;
    int end = offset + length;
    int start = offset;

    // Handle leading NUL
    if (buffer[start] == 0) {
        return 0L;
    }

    // Skip leading spaces
    while (start < end && buffer[start] == ' ') {
        start++;
    }

    // Trim trailing NULs and spaces
